    private bool isConnecting = false;
    private string? connectionMessage;
    private string? selectedCompanyCode;

    private async Task SelectCompany(MobileCheckResponse comp)
    {
        await CompanyService.SetSelectedCompanyAsync(comp);
        isConnecting = true;
        selectedCompanyCode = comp.CompanyCode;
        connectionMessage = null;

        // call API to establish DB connection
        var result = await AuthService.ConnectCompanyAsync(comp.CompanyCode ?? "", comp.LicenceKey ?? "");
        if (result.IsSuccess)
        {
            // navigate to company login screen
            Navigation.NavigateTo("/company-login");
        }
        else
        {
            connectionMessage = result.Message;
            isConnecting = false;
            selectedCompanyCode = null;
        }
    }

    private void GoBack()
    {
        Navigation.NavigateTo("/mobile-verification");
    }

